// ============================================================================
// SHAPE PATHS  — used by both pages
// ============================================================================
function shapePath(shape, r) {
  switch (shape) {
    case 'circle':
      return `M0,${-r} a${r},${r} 0 1,0 0.001,0 z`;
    case 'square':
      return `M${-r},${-r} h${r*2} v${r*2} h${-r*2} z`;
    case 'rsquare': {
      // rounded square
      const k = r * 0.3;
      return `M${-r+k},${-r} h${r*2-k*2} q${k},0 ${k},${k} v${r*2-k*2} q0,${k} ${-k},${k} h${-(r*2-k*2)} q${-k},0 ${-k},${-k} v${-(r*2-k*2)} q0,${-k} ${k},${-k} z`;
    }
    case 'diamond':
      return `M0,${-r*1.15} L${r*1.15},0 L0,${r*1.15} L${-r*1.15},0 z`;
    case 'hex': {
      // pointy-top hexagon
      const a = r * 1.05;
      const h = a * Math.sqrt(3)/2;
      return `M0,${-a} L${h},${-a/2} L${h},${a/2} L0,${a} L${-h},${a/2} L${-h},${-a/2} z`;
    }
    case 'trap': {
      // trapezoid (OSAT — back-end services)
      return `M${-r*1.1},${r*0.7} L${-r*0.7},${-r*0.7} L${r*0.7},${-r*0.7} L${r*1.1},${r*0.7} z`;
    }
    default:
      return `M0,${-r} a${r},${r} 0 1,0 0.001,0 z`;
  }
}

// ============================================================================
// FONT INJECTION
// ============================================================================
function useFonts() {
  useEffect(() => {
    const id = 'semicon-fonts';
    if (document.getElementById(id)) return;
    const link = document.createElement('link');
    link.id = id;
    link.href = 'https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght,SOFT@9..144,300..900,0..100&family=IBM+Plex+Mono:wght@300;400;500;600&family=IBM+Plex+Sans:wght@300;400;500;600;700&display=swap';
    link.rel = 'stylesheet';
    document.head.appendChild(link);
    return () => { /* keep loaded */ };
  }, []);
}

// ============================================================================
// HELPERS
// ============================================================================
function clusterCentroids(companies) {
  const groups = {};
  for (const c of companies) {
    if (c.lat == null || c.lng == null) continue;
    const cid = c.geo_cluster_id;
    if (!groups[cid]) groups[cid] = { id: cid, lat: 0, lng: 0, total_scale: 0, members: [] };
    groups[cid].lat += c.lat;
    groups[cid].lng += c.lng;
    groups[cid].total_scale += (c.scale_indicator || 30);
    groups[cid].members.push(c);
  }
  Object.values(groups).forEach(g => {
    g.lat /= g.members.length;
    g.lng /= g.members.length;
    g.label = g.id.replace(/^metro_/,'').replace(/^country_/,'').replace(/_/g,' ');
  });
  return groups;
}

// ============================================================================
// SEARCH BAR
// ============================================================================
function SearchBar({ companies, page, selected, setSelected }) {
  const [query, setQuery] = useState('');
  const [open, setOpen] = useState(false);
  const inputRef = useRef(null);

  const pageCompanies = useMemo(() =>
    companies.filter(c => c.page === page || c.page === 'both'),
    [companies, page]
  );

  const results = useMemo(() => {
    if (!query.trim()) return [];
    const q = query.toLowerCase();
    return pageCompanies.filter(c => c.name.toLowerCase().includes(q)).slice(0, 8);
  }, [query, pageCompanies]);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === '/' && document.activeElement.tagName !== 'INPUT') {
        e.preventDefault();
        inputRef.current?.focus();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  const pick = (id) => {
    setSelected(id);
    setQuery('');
    setOpen(false);
    inputRef.current?.blur();
  };

  const clear = (e) => {
    e.stopPropagation();
    setSelected(null);
    setQuery('');
    setOpen(false);
  };

  const selectedName = selected ? companies.find(c => c.id === selected)?.name : null;
  const mono = { fontFamily: 'IBM Plex Mono, monospace' };

  return (
    <div style={{ position: 'relative', width: 220 }}>
      <div style={{
        display: 'flex', alignItems: 'center', gap: 6,
        background: 'var(--surface)',
        border: '1px solid', borderColor: open ? 'var(--border-bright)' : 'var(--border)',
        padding: '5px 10px', transition: 'border-color 0.15s',
      }}>
        <span style={{ ...mono, fontSize: 13, color: 'var(--text-dim)', flexShrink: 0 }}>⌕</span>
        <input
          ref={inputRef}
          value={query}
          onChange={e => { setQuery(e.target.value); setOpen(true); }}
          onFocus={() => setOpen(true)}
          onBlur={() => setTimeout(() => setOpen(false), 120)}
          onKeyDown={e => { if (e.key === 'Escape') { setQuery(''); setOpen(false); inputRef.current.blur(); } }}
          placeholder={selectedName ?? 'Search companies… (/)'}
          style={{
            ...mono, fontSize: 11,
            background: 'transparent', border: 'none', outline: 'none',
            color: 'var(--text)', width: '100%', minWidth: 0,
          }}
        />
        {selected && !query && (
          <button onMouseDown={clear} style={{ ...mono, fontSize: 11, color: 'var(--text-dim)', background: 'none', border: 'none', cursor: 'pointer', padding: 0, lineHeight: 1, flexShrink: 0 }}>✕</button>
        )}
        {!selected && <span style={{ ...mono, fontSize: 9, color: 'var(--text-dim)', flexShrink: 0 }}>/</span>}
      </div>
      {open && results.length > 0 && (
        <div style={{
          position: 'absolute', top: 'calc(100% + 2px)', left: 0, right: 0,
          background: 'var(--surface)', border: '1px solid var(--border-bright)',
          zIndex: 100, maxHeight: 260, overflowY: 'auto',
        }}>
          {results.map(c => (
            <button
              key={c.id}
              onMouseDown={() => pick(c.id)}
              style={{
                display: 'flex', alignItems: 'baseline', gap: 8,
                width: '100%', textAlign: 'left',
                padding: '7px 10px', background: 'none',
                border: 'none', borderBottom: '1px solid var(--border)',
                cursor: 'pointer', color: 'var(--text)',
              }}
              onMouseEnter={e => e.currentTarget.style.background = 'var(--surface-2)'}
              onMouseLeave={e => e.currentTarget.style.background = 'none'}
            >
              <span style={{ fontFamily: 'IBM Plex Sans, sans-serif', fontSize: 12 }}>{c.name}</span>
              <span style={{ ...mono, fontSize: 9, color: 'var(--text-dim)' }}>{c.node_type}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

